  const [ops, argLists] = args;
  if (!Array.isArray(outputs) || outputs.length !== ops.length) return false;
  const counts = new Map();
  for (let i = 1; i < ops.length; i++) {
    const op = ops[i], a = argLists[i], out = outputs[i];
    if (op === 'insert') {
      const v = a[0];
      const expected = (counts.get(v) || 0) === 0;
      if (out !== expected) return false;
      counts.set(v, (counts.get(v) || 0) + 1);
    } else if (op === 'remove') {
      const v = a[0];
      const expected = (counts.get(v) || 0) > 0;
      if (out !== expected) return false;
      if (expected) {
        const c = counts.get(v) - 1;
        if (c === 0) counts.delete(v); else counts.set(v, c);
      }
    } else if (op === 'getRandom') {
      if (!counts.has(out) || counts.get(out) <= 0) return false;
    }
  }
  return true;
