import random
from collections import defaultdict


class RandomizedCollection:
    def __init__(self):
        self.items = []
        self.pos = defaultdict(set)
    def insert(self, val):
        present = len(self.pos[val]) > 0
        self.pos[val].add(len(self.items))
        self.items.append(val)
        return not present
    def remove(self, val):
        if not self.pos[val]:
            return False
        remove_idx = next(iter(self.pos[val]))
        self.pos[val].discard(remove_idx)
        last_idx = len(self.items) - 1
        last_val = self.items[last_idx]
        if remove_idx != last_idx:
            self.items[remove_idx] = last_val
            self.pos[last_val].discard(last_idx)
            self.pos[last_val].add(remove_idx)
        self.items.pop()
        return True
    def getRandom(self):
        return random.choice(self.items)

