var RandomizedCollection = function() {
    this.items = [];
    this.pos = new Map();
};
RandomizedCollection.prototype.insert = function(val) {
    if (!this.pos.has(val)) this.pos.set(val, new Set());
    const set = this.pos.get(val);
    const present = set.size > 0;
    set.add(this.items.length);
    this.items.push(val);
    return !present;
};
RandomizedCollection.prototype.remove = function(val) {
    const set = this.pos.get(val);
    if (!set || set.size === 0) return false;
    const removeIdx = set.values().next().value;
    set.delete(removeIdx);
    const lastIdx = this.items.length - 1;
    const lastVal = this.items[lastIdx];
    if (removeIdx !== lastIdx) {
        this.items[removeIdx] = lastVal;
        const lastSet = this.pos.get(lastVal);
        lastSet.delete(lastIdx);
        lastSet.add(removeIdx);
    }
    this.items.pop();
    return true;
};
RandomizedCollection.prototype.getRandom = function() {
    return this.items[Math.floor(Math.random() * this.items.length)];
};
